"""Functions for loading packaged YAML databases."""from importlib.resources import filesimport yaml_SETTINGS = Nonedef load_settings_database() -> dict:    """    Load the CRIRES+ settings database.    Returns    -------    dict        Dictionary containing all CRIRES+ settings.    """    global _SETTINGS    if _SETTINGS is None:        path = files("criresviz.database").joinpath("crires_settings.yaml")        with path.open("r", encoding="utf-8") as stream:            _SETTINGS = yaml.safe_load(stream)        return _SETTINGS